INSERT INTO cs_faq (cs_faq_id, category, question, answer, use_yn, tags, created_at, updated_at) VALUES 
('FAQ0000000001', '공통', '카카오 알림톡/브랜드메시지는 무엇인가요?', '카카오 알림톡과 브랜드메시지는 카카오톡에서 제공하는 기업 Push 메시지 서비스입니다. 공식딜러를 통해서 사용가능하며, 플러스친구ID 기반으로 제공됩니다.', 'Y', '공통,알림톡,브랜드메시지,카카오톡', NOW(), NOW()),
('FAQ0000000002', '공통', '플러스친구를 꼭 가입해야 하나요?', '알림톡과 브랜드메시지를 이용하기 위해선 반드시 플러스친구 가입을 해야합니다. 하지만 문자서비스만 이용하실 경우 플러스친구 가입은 안하셔도 무방합니다.', 'Y', '공통,플러스친구,가입,카톡', NOW(), NOW()),
('FAQ0000000003', '공통', '카카오톡으로만 보낼 수 있나요?', '톡드림 서비스는 선택하신 채널(앱)로만 선별하여 전송이 가능합니다. 기존 카카오톡, MPOST 외 추가적으로 연결하고자 하는 앱이 있는 경우, 별도 서비스 사용료가 부가됩니다. 카카오톡으로만 전송을 선택하시는 경우, 고객의 앱설치 유무, 네트워크 환경에 따라서 수신이 안될 수 있습니다. 따라서 실패시 SMS로 대체 발송 처리하시는걸 추천드립니다.', 'Y', '공통,카카오톡,전송채널,SMS대체', NOW(), NOW()),
('FAQ0000000004', '공통', '서비스 이용절차가 궁금합니다.', '서비스는 선불결제방식과 후불결제방식 중 하나를 선택하여 이용가능합니다. [선불결제방식]은 포탈에서 회원가입을 하신 후, 차례로 플러스친구 등록 및 인증, 템플릿 등록, 발신번호 등록, 포인트 충전 등의 절차를 거치신후 메시지 웹발송을 할 수 있습니다. 자세한 내역은 회원 가입 후 로그인하시면 필요한 절차를 안내받으실 수 있습니다. 회원가입은 사업자번호를 가지고 계신 법인 고객만 가능합니다. [후불결제방식]은 월 1만 건 이상의 대량 발송이 필요한 기업고객의 경우 선택이 가능한 서비스 입니다. 회원가입 대신 저희 영업대표를 통해 직접 상담후 별도의 계약을 체결하며, LG CNS에서 제공해드리는 연동모듈인 \'Agent\'를 설치하여 대량 발송을 할 수 있습니다. 이 경우 이용 금액은 후불로 정산되므로 사전에 따로 결제하실 필요는 없습니다.', 'Y', '공통,이용절차,선불,후불,회원가입', NOW(), NOW()),
('FAQ0000000005', '공통', '후불회원 신청하는 절차는 어떻게 되나요?', '상단에 위치한 \'서비스 신청\' 메뉴를 클릭 하신 뒤 \'서비스 문의\' 메뉴를 통해 상담 신청을 해주시면 담당자가 직접 연락드린 뒤 상세 안내 드립니다.', 'Y', '공통,후불회원,신청절차,상담', NOW(), NOW()),
('FAQ0000000006', '공통', '회원가입이 되지 않습니다.', '회원가입은 법인 고객만 가능하시며, 만일 이전에 다른 사용자분이 해당 법인정보로 회원가입을 한 경우에는 회원가입이 불가능합니다. 현재는 법인당 1개 회원만 회원가입 가능합니다.', 'Y', '공통,회원가입,법인회원', NOW(), NOW()),
('FAQ0000000007', '공통', '세금계산서 발행 가능한가요?', '네, 가능합니다.', 'Y', '공통,세금계산서,발행', NOW(), NOW()),
('FAQ0000000008', '공통', '발송 속도는 얼마나 되나요? (안드로이드 / IOS)', '98%가 10초 이내에 도착합니다. ※ 발송서버에서 데이타를 가져와 카카오로 던진 후 카카오 알림톡 수신일시 회신 기준', 'Y', '공통,발송속도,수신일시', NOW(), NOW()),
('FAQ0000000009', '결제 / 환불', '결제수단은 신용카드밖에 안되나요?', '현재 결제수단은 신용카드만 사용 가능합니다.', 'Y', '결제,환불,결제수단,신용카드', NOW(), NOW()),
('FAQ0000000010', '결제 / 환불', '신용카드는 모든 카드가 사용 가능한가요?', '신용카드는 모든 카드로 결제 가능합니다.', 'Y', '결제,환불,카드종류', NOW(), NOW()),
('FAQ0000000011', '결제 / 환불', '결제 내역을 취소할 수 있나요?', '결제하신후 3개월내에 한번도 사용하지 않은 결제건에 대해서는 취소가 가능합니다. 단, 결제후 부여받은 포인트중 한번이라도 웹발송을 사용했던 결제 건에 대해서는 취소가 되지 않으니 이점 양지하시기 바랍니다.', 'Y', '결제,환불,결제취소,포인트', NOW(), NOW()),
('FAQ0000000012', '결제 / 환불', '결제내역을 보고 카드매출전표를 출력 하고 싶습니다.', '결제내역을 보시려면 포인트 관리 -> 충전/차감 내역 조회 메뉴에서 확인 및 매출전표를 출력 하실 수 있습니다.', 'Y', '결제,환불,매출전표,출력', NOW(), NOW()),
('FAQ0000000013', '결제 / 환불', '포인트는 사용기한이 따로 있나요?', '포인트는 부여받으신 후 5년 안에 사용하시면 됩니다. 5년이 경과하였음에도 사용되지 않은 포인트에 대해서는 자동소멸되오니 참고하시기 바랍니다.', 'Y', '결제,환불,포인트기한,소멸', NOW(), NOW()),
('FAQ0000000014', '결제 / 환불', '포인트 환불을 받고 싶습니다.', '가입해지 시점에 남아있는 포인트에 대해서는 해지하시기 전에 1:1 문의에서 환불요청을 해주시면 정산 후 환불 가능합니다. 환불은 소속 법인의 법인계좌로만 환불이 가능합니다. 계산 예 - 잔여포인트 : 9000(잔여포인트) + 900(부가세 10%, 소수점 이하 절사) = 9900원(환불금액)', 'Y', '결제,환불,포인트환불,계좌환불', NOW(), NOW()),
('FAQ0000000015', '결제 / 환불', '포인트 차감 기준은 어떻게 되나요?', '포인트 차감은 당사의 가격정책과 포인트 차감정책에 따라 채널별로 다르게 차감됩니다. 포인트 관리 -> 가격 안내 및 충전 메뉴에서 확인 가능합니다. 메시지 발송이 실패하였을 경우에는 차감된 포인트를 원래대로 원복시켜 드립니다.', 'Y', '결제,환불,차감기준,환급', NOW(), NOW()),
('FAQ0000000016', '발송', '카카오에서 플러스친구를 생성했는데 등록이 안됩니다.', '플러스친구는 기업회원으로 생성하셔야하며, 생성 시 관리자 인증이 필요합니다. 또한 플러스친구 상세설정에서 공개설정을 \'홈공개\' ON으로 설정해주셔야, 등록/사용이 가능합니다. 플러스친구 등록상태를 다시한번 살펴봐주시기 바랍니다.', 'Y', '발송,플러스친구,등록에러,홈공개', NOW(), NOW()),
('FAQ0000000017', '발송', '브랜드메시지를 보낼 때 이미지 사이즈에 제한이 있나요?', '브랜드메시지 이미지 사이즈는 아래와 같이 제한이 있습니다. * 권장 사이즈: 800 X 400px (가로 500px 이상) * 이미지 비율: 0.5 ≤ 세로 ÷ 가로 ≤ 1.333 * 파일 형식 및 용량 제한: jpg, png / 최대 5MB * 기타 브랜드메시지 세부 유형에 따라 업로드 가능 규격 차이가 있을 수 있습니다. 업로드 시 안내된 가이드에 따라 진행해주시면 됩니다.', 'Y', '발송,이미지사이즈,규격,브랜드메시지', NOW(), NOW()),
('FAQ0000000018', '발송', '타사에서 알림톡, 브랜드메시지를 사용하고 있습니다. 톡드림 서비스로 변경하여 사용 할 수 있나요?', '가능합니다. 단, 타사에서 사용하셨던 알림톡 템플릿은 톡드림 서비스에서 재등록 후 다시 신청을 받으셔야합니다.', 'Y', '발송,서비스변경,템플릿재등록', NOW(), NOW()),
('FAQ0000000019', '발송', '친구 차단하면 알림톡도 차단이 되나요?', '수신자가 플러스친구 친구차단을 하더라도 카카오 알림톡 수신은 가능합니다. 물론 수신자가 알림톡 차단을 원할 경우, 채팅방에서 ‘알림톡 받지 않기’ 버튼을 통해 수신거부가 가능합니다.', 'Y', '발송,친구차단,알림톡수신,수신거부', NOW(), NOW()),
('FAQ0000000020', '발송', '카카오 알림톡으로 광고성 문자발송이 가능 한가요?', '알림톡은 광고성 문자발송이 불가능합니다. 톡드림 서비스에서는 수시 모니터링을 통하여, 알림톡으로 어뷰징 발송을 강력히 제재 하고 있습니다. 계속적인 어뷰징 시도 시에는 강제 아이디 차단 및 발송금지의 조치를 취하고 있습니다. 광고성 문자 발송을 하셔야 되는 고객님께서는 브랜드메시지나 문자 발송을 사용하시기 바랍니다.', 'Y', '발송,광고성문자,알림톡제한,어뷰징', NOW(), NOW()),
('FAQ0000000021', '발송', '템플릿은 왜 등록해야 하나요?', '문자 서비스나 브랜드메시지 자유형 서비스 이용 시에는 템플릿 등록이 필요없습니다. 그러나 알림톡 서비스의 경우에는 반드시 등록이 필요합니다. 알림톡 서비스는 정보성 서비스이기 때문에 사전에 보내려는 내용이 광고성인지 정보성인지 검수가 하는 과정이 필요하며, 템플릿 등록을 통해서 검수가 이루어지고 있습니다.', 'Y', '발송,템플릿등록,검수이유,정보성', NOW(), NOW()),
('FAQ0000000022', '발송', '템플릿 검수기간은 얼마나 걸리나요?', '검수 요청 후 검수와 관련된 모든 권한은 카카오측에 있기 때문에 검수기간에 대해서는 특정해 드릴 수 없는 점 양해 바랍니다. 보통 업무일 기준 2~3일 정도 소요됩니다.', 'Y', '발송,검수기간,카카오검수', NOW(), NOW()),
('FAQ0000000023', 'Agent', 'Agent(연동 모듈)방식은 개발공수가 많이 들어갈까요? 서비스 오픈까지 얼마나 걸릴까요?', 'Agent(연동 모듈)를 이용한 발송 방식은 1만 건 이상의 대량 발송이 필요하며, 이를 관리하기 위해 고객사에서 자체적으로 관리하는 DB가 있는 경우에만 이용이 가능 합니다. 고객사에서는 자사가 제공하는 Agent를 서버에 설치하시어 자사 테이블에 데이터만 넣어주시면 되며, 서비스 오픈을 위해 필요한 사전 작업(방화벽 셋팅, 템플릿 등록 및 Agent 설치/테스트 등)이 존재하기 때문에 진행에 약 4-5주 정도 소요 됩니다.', 'Y', 'Agent,대향발송,DB연동,오픈기간', NOW(), NOW()),
('FAQ0000000024', 'Agent', '서비스 이용을 위한 서버/DB 사양이 궁금합니다.', '[ Agent 설치 서버 권장 사양 ] 1. CPU 2.x Ghz 2core 이상 2. Memory : 4Gbyte 이상 3. disk : 100Gbyte 이상(data 발송 및 로깅 처리) 4. DB table space : 발송data 1건기준 16kbyte(최대) = 평균 9kbyte 100만건 기준으로 약 1G 미만 ※ 데이타 저장공간은 저장기간에 따라 필요한 size입니다. [ 설치 대상 서버 조건 ] 1. Server OS 환경 - Windows, Linux, AIX, Solaris 지원 2. Server DBMS환경 - ORACLE xx, MSSQL, MySQL : ver 5 이상 - DB2 : ver 9.7 이상, pagesize 32 k 이상 필요 ※ JAVA - JDK 1.6 이상 필요 (Windows 서비스 등록시 JDK 1.7일 경우 지원됨 )', 'Y', 'Agent,서버사양,DB환경,권장사양', NOW(), NOW());
